//! Embedded static-asset handler for the SPA bundle.
//!
//! `web/dist/` is generated by `pnpm build` and slurped into the binary via
//! `rust-embed` at compile time. If the directory is missing or empty (for
//! example, on a developer machine that hasn't run the frontend build yet)
//! the `Assets` struct still derives — it just contains zero entries, and
//! the handler responds with `404` for everything except the SPA fallback.
//!
//! The handler implements an SPA-friendly fallback: requests whose path
//! contains a `.` are treated as asset requests (and 404 if missing); paths
//! without a `.` fall through to `index.html` so client-side routes don't
//! 404. API routes registered via `Router::route(...)` always take precedence
//! because Axum dispatches `route` matches before the `fallback`.
//!
//! This module is wired into the router in `lib.rs::build_router`.

use axum::body::Body;
use axum::http::{StatusCode, Uri, header};
use axum::response::{IntoResponse, Response};
use rust_embed::Embed;

#[derive(Embed)]
#[folder = "web/dist/"]
struct Assets;

/// Path inside the embed for the SPA entry point. `rust-embed` uses
/// forward slashes regardless of host OS.
const INDEX_HTML: &str = "index.html";

/// Look up `path` in the embed; if absent, fall through to `index.html` when
/// the request looks like a client-side route (no extension), or `None` when
/// it looks like a missing asset (has a `.`).
///
/// Exposed pure for unit testing. The HTTP handler wraps this with status
/// code translation.
pub(crate) fn resolve_asset(path: &str) -> AssetLookup<'_> {
    if let Some(file) = Assets::get(path) {
        return AssetLookup::Hit { path, file };
    }
    if path.contains('.') {
        return AssetLookup::Missing;
    }
    if let Some(file) = Assets::get(INDEX_HTML) {
        return AssetLookup::SpaFallback { file };
    }
    AssetLookup::Missing
}

pub(crate) enum AssetLookup<'a> {
    Hit {
        path: &'a str,
        file: rust_embed::EmbeddedFile,
    },
    SpaFallback {
        file: rust_embed::EmbeddedFile,
    },
    Missing,
}

/// Axum handler: resolves the URI against the embed, falling through to
/// `index.html` for unknown extensionless paths so SPA routes work, and
/// returning 404 for misses on paths that look like assets.
pub async fn static_handler(uri: Uri) -> Response {
    let raw_path = uri.path();
    let trimmed = raw_path.trim_start_matches('/');
    let path = if trimmed.is_empty() {
        INDEX_HTML
    } else {
        trimmed
    };

    match resolve_asset(path) {
        AssetLookup::Hit {
            path: hit_path,
            file,
        } => embedded_response(hit_path, file),
        AssetLookup::SpaFallback { file } => embedded_response(INDEX_HTML, file),
        AssetLookup::Missing => not_found(),
    }
}

fn embedded_response(path: &str, file: rust_embed::EmbeddedFile) -> Response {
    let mime = mime_guess::from_path(path).first_or_octet_stream();
    let body = Body::from(file.data.into_owned());
    Response::builder()
        .status(StatusCode::OK)
        .header(header::CONTENT_TYPE, mime.as_ref())
        .body(body)
        .unwrap_or_else(|_| {
            (StatusCode::INTERNAL_SERVER_ERROR, "static response error").into_response()
        })
}

fn not_found() -> Response {
    (StatusCode::NOT_FOUND, "not found").into_response()
}

#[cfg(test)]
mod tests {
    use super::*;

    fn web_dist_present() -> bool {
        std::path::Path::new(env!("CARGO_MANIFEST_DIR"))
            .join("web/dist/index.html")
            .is_file()
    }

    #[test]
    fn missing_asset_with_dot_returns_missing() {
        match resolve_asset("foo/missing.js") {
            AssetLookup::Missing => {}
            _ => panic!("expected Missing for asset-shaped path"),
        }
    }

    #[test]
    fn extensionless_unknown_path_uses_spa_fallback_when_index_present() {
        if !web_dist_present() {
            eprintln!("web/dist not built; skipping spa-fallback unit test");
            return;
        }
        match resolve_asset("some/route") {
            AssetLookup::SpaFallback { .. } => {}
            _ => panic!("expected SpaFallback when index.html is embedded"),
        }
    }

    #[test]
    fn index_html_resolves_to_hit_when_present() {
        if !web_dist_present() {
            eprintln!("web/dist not built; skipping index-hit unit test");
            return;
        }
        match resolve_asset("index.html") {
            AssetLookup::Hit { path, .. } => assert_eq!(path, "index.html"),
            _ => panic!("expected Hit for index.html"),
        }
    }
}
